/* {{pp-template}} */
/* [[phab:T360683]]: This stylesheet removes the function of this template in
 * dark mode
 */

@media screen {
    html.skin-theme-clientpref-night div:not(.notheme) > .tmp-color,
	html.skin-theme-clientpref-night p > .tmp-color,
	html.skin-theme-clientpref-night table:not(.notheme) .tmp-color {
	   color: inherit !important;
	}
}

@media screen and ( prefers-color-scheme: dark) {
    /* automatic mode */
    html.skin-theme-clientpref-os div:not(.notheme) > .tmp-color,
    html.skin-theme-clientpref-os p > .tmp-color,
    html.skin-theme-clientpref-os table:not(.notheme) .tmp-color {
      color: inherit !important;
    }
}

/* Template:Color will not work in night theme. If the colors are semantically important for your article, and it is important these colors appear in night mode, it is suggested you create a template specifically targeted at your use case rather than using the generic color template. */

html.skin-theme-clientpref-night .tmp-color {
   color: inherit !important;
}
@media (prefers-color-scheme: dark) {
    /* automatic mode */
    html.skin-theme-clientpref-os .tmp-color {
      color: inherit !important;
    }
}

